+		}
+	}
+
+	// Apply final filtering:
+	CTimeLoggerEntry tleFilter(m_profiler, "on_do_publish.apply_final_pipeline");
+
+	mp2p_icp_filters::apply_filter_pipeline(m_final_pipeline, mm);
