+			m_gui_win->unlockAccess3DScene();
+		}
+
+		// Process key ops on the gui:
+		if (m_gui_win->keyHit())
+		{
+			const auto key = m_gui_win->getPushedKey();
+			m_gui_win->clearKeyHitFlag();
+			switch (key)
+			{
+				case '1':
+					m_visible_raw = !m_visible_raw;
+					break;
+
+				case '2':
