+		gl_obs->clear();
+
+		auto glRawPts =
+			mrpt::ptr_cast<mrpt::opengl::CPointCloud>::from(scene->getByName("raw_points"));
+
+		auto glFinalPts =
+			mrpt::ptr_cast<mrpt::opengl::CPointCloud>::from(scene->getByName("final_points"));
+
+		scene->getViewport()->addTextMessage(
+			5, 25,
+			mrpt::format(
