+				m_visible_output ? "VISIBLE" : "hidden"),
+			1);
+
+		for (const auto& o : obs)
+		{
+			const InfoPerTimeStep& ipt = o.second;
+			// Relative pose in the past:
+			mrpt::poses::CPose3D relPose(mrpt::poses::UNINITIALIZED_POSE);
